INSERT INTO `_meta_tables` (`table_name`, `description_vi`, `description_en`, `business_context`, `data_source`) VALUES
('ports', 'Danh sách cảng biển/ICD liên quan: Gemadept và đối thủ', 'Catalog of ports/ICDs: Gemadept ports + competitors', 'Phân biệt qua is_gemadept. Cluster gồm: Hải Phòng, CM-TV (Cái Mép-Thị Vải), HCM, Miền Trung.', 'Internal'),
('shipping_lines', '25 hãng tàu container hoạt động tại VN — top 10 global + regional', '25 container shipping lines active in VN — top 10 global + regional', 'Bao gồm fleet size, ranking toàn cầu. Dùng để cross-reference với alliance_membership_history.', 'Internal/Linerlytica'),
('alliances', '7 liên minh: 3 cũ (giải thể 1/2025) + 4 mới (từ 2/2025)', '7 alliances: 3 legacy (dissolved Jan 2025) + 4 current (since Feb 2025)', 'Tái cấu trúc 2/2025: 2M tan rã, THE Alliance → Premier, Ocean Alliance gia hạn, Gemini ra đời, MSC standalone.', 'Industry'),
('alliance_membership_history', 'Lịch sử thành viên liên minh — line × alliance × period', 'Membership history — line × alliance × period', 'Critical cho phân tích trước/sau Feb 2025. Một line có thể thuộc nhiều alliance trong các thời kỳ khác nhau.', 'Industry'),
('vessels', '~120 tàu container thực tế đang hoạt động tuyến VN', '~120 real container vessels operating VN routes', 'Mega ≥200k DWT (chỉ Gemalink đón được), large 100-200k, medium 50-100k, feeder <50k.', 'Internal/IMO'),
('services', '30 tuyến dịch vụ container có ghé VN', '30 container services calling VN ports', 'Bao gồm tên dịch vụ thật (FE1, EC5, AE1, Tropic, ZX2), trade lane, port rotation, alliance vận hành.', 'Industry'),
('news_events', '~60 sự kiện ngành 2024-2026 ảnh hưởng đến hoạt động cảng', '~60 industry events 2024-2026 affecting port operations', 'Categories: alliance, route, regulation, tariff, weather, competitor. Chứa thông tin Feb 2025 reshuffle, Feb 2026 price hike, Trump tariff.', 'Phaata/Vietstock/Lloyd List'),
('customers_shippers', '45 shipper/khách hàng XNK lớn dùng dịch vụ cảng', '45 large shippers/customers using port services', 'Industry: Electronics, Apparel, Textile, Steel, Furniture, Seafood... primary_region cho biết miền chính.', 'Internal CRM'),
('port_calls', 'Transaction-level: mỗi lần tàu cập cảng Gemadept (2024-04 → 2026-03)', 'Transaction-level: every vessel call at Gemadept ports (2024-04 to 2026-03)', 'Grain: 1 row = 1 port call. Bao gồm ETA/ETB/ETD + ATA/ATB/ATD, TEU handled, revenue, cost.', 'Internal SmartPort/CATOS'),
('daily_port_stats', 'Aggregated daily — fast query cho dashboard', 'Daily aggregated stats for dashboard fast queries', 'Chỉ Gemadept ports. Có total_teu, total_calls, total_revenue_vnd, unique_lines_count.', 'Internal (derived from port_calls)'),
('port_vessel_schedule_external', 'Lịch tàu CÔNG KHAI từ cảng vụ — TẤT CẢ cảng (Gemadept + đối thủ)', 'Public vessel schedule from Cảng Vụ — ALL ports (Gemadept + competitors)', 'CRITICAL cho cross-reference. Chứa data đối thủ. Source: cangvuhaiphong, cangvuvungtau, cangvuhcm.', 'Public — Cảng Vụ'),
('pricing_tariff', 'Giá sàn xếp dỡ theo cảng × hãng × thời kỳ', 'Stevedoring tariff by port × line × period', 'Top 5 line: 0.95×base, Medium: 1.00×, Small: 1.05×. Deepsea +10% từ 2026-02-01 (QĐ 810 sửa đổi).', 'Internal');
