INSERT INTO `_meta_kpi` (`kpi_name`, `formula_sql`, `description_vi`, `related_questions`) VALUES
('TEU Throughput', 'SELECT SUM(total_teu_handled) FROM port_calls WHERE eta BETWEEN ? AND ?', 'Tổng TEU thông qua cảng (load + discharge + transshipment)', 'Câu 1, 2, 5'),
('TEU Throughput by Alliance', 'SELECT a.alliance_name, SUM(pc.total_teu_handled) FROM port_calls pc JOIN alliance_membership_history m ON m.line_id=pc.shipping_line_id AND m.from_date<=DATE(pc.eta) AND (m.to_date IS NULL OR m.to_date>=DATE(pc.eta)) JOIN alliances a ON m.alliance_id=a.alliance_id GROUP BY a.alliance_name', 'TEU theo liên minh hãng tàu (theo thời điểm) — quan trọng cho phân tích trước/sau Feb 2025', 'Câu 1, 5'),
('TEU Throughput by Line', 'SELECT shipping_line_id, SUM(total_teu_handled) FROM port_calls GROUP BY shipping_line_id', 'TEU theo hãng tàu', 'Câu 1, 2, 6'),
('Port Call Frequency', 'SELECT port_id, shipping_line_id, COUNT(*) FROM port_calls GROUP BY port_id, shipping_line_id', 'Số lần tàu cập cảng theo hãng', 'Câu 2, 3, 4'),
('Market Share within Cluster', 'WITH cluster_total AS (SELECT p.cluster, SUM(pvs.teu_capacity_est) total FROM port_vessel_schedule_external pvs JOIN ports p ON pvs.port_id=p.port_id GROUP BY p.cluster) SELECT pvs.port_id, p.port_name, SUM(pvs.teu_capacity_est)/ct.total*100 share FROM port_vessel_schedule_external pvs JOIN ports p ON pvs.port_id=p.port_id JOIN cluster_total ct ON p.cluster=ct.cluster GROUP BY pvs.port_id', 'Thị phần TEU ước tính trong cụm cảng (Gemalink trong CM-TV...)', 'Câu 3'),
('Wallet Share per Line', 'SELECT pc.shipping_line_id, SUM(pc.total_teu_handled) gemadept_teu, (SELECT SUM(pvs.teu_capacity_est) FROM port_vessel_schedule_external pvs WHERE pvs.shipping_line_id=pc.shipping_line_id) total_vn_capacity FROM port_calls pc GROUP BY pc.shipping_line_id', '% sản lượng VN của hãng đi qua Gemadept', 'Câu 4, 6'),
('BD Opportunity Gap', 'WITH cm_tv AS (SELECT pvs.shipping_line_id, COUNT(*) c FROM port_vessel_schedule_external pvs JOIN ports p ON pvs.port_id=p.port_id WHERE p.cluster=\'CM-TV\' AND p.port_name<>\'Gemalink\' AND eta>=DATE_SUB(CURDATE(),INTERVAL 6 MONTH) GROUP BY pvs.shipping_line_id), gml AS (SELECT shipping_line_id, COUNT(*) c FROM port_calls WHERE port_id=\'P006\' AND eta>=DATE_SUB(CURDATE(),INTERVAL 6 MONTH) GROUP BY shipping_line_id) SELECT cm_tv.shipping_line_id, cm_tv.c-COALESCE(gml.c,0) gap FROM cm_tv LEFT JOIN gml USING(shipping_line_id) ORDER BY gap DESC', 'Gap port_call: hãng đang ghé CM-TV nhưng ít/không ghé Gemalink', 'Câu 4'),
('Revenue THC', 'SELECT SUM(revenue_vnd-vas_revenue_vnd) FROM port_calls', 'Doanh thu xếp dỡ (THC) — không tính VAS', 'Câu 7, 8'),
('Total Revenue', 'SELECT SUM(revenue_vnd) FROM port_calls', 'Tổng doanh thu (THC + VAS)', 'Câu 1, 6, 7'),
('Gross Margin', 'SELECT (SUM(revenue_vnd)-SUM(cost_vnd))/SUM(revenue_vnd)*100 FROM port_calls', 'Biên lợi nhuận gộp — Gemalink target ~44%', 'Câu 6, 7'),
('Reefer Mix', 'SELECT SUM(reefer_teu)/SUM(total_teu_handled)*100 FROM port_calls', '% TEU lạnh trong tổng TEU', 'Operational'),
('Avg Dwell Time', 'SELECT AVG(dwell_time_hours) FROM port_calls', 'Thời gian tàu nằm bến trung bình (giờ)', 'Operational efficiency');
INSERT INTO `_meta_glossary` (`term_vi`, `term_en`, `definition`, `related_tables`) VALUES
('TEU', 'Twenty-foot Equivalent Unit', 'Đơn vị quy đổi 1 container 20 feet. Tàu mega có sức chứa 23k TEU.', 'vessels, port_calls'),
('DWT', 'Deadweight Tonnage', 'Trọng tải toàn phần tàu (tonne). Gemalink đón tàu tới 250k DWT.', 'vessels, ports'),
('Port Call', 'Vessel Port Call', 'Một lần tàu cập cảng để xếp dỡ.', 'port_calls, port_vessel_schedule_external'),
('THC', 'Terminal Handling Charge', 'Phí xếp dỡ tại cảng — chiếm 60-70% doanh thu cảng.', 'pricing_tariff, port_calls.revenue_vnd'),
('VAS', 'Value-Added Service', 'Dịch vụ giá trị gia tăng (CFS, đóng rút cont, reefer monitoring).', 'port_calls.vas_revenue_vnd'),
('Liên minh hãng tàu', 'Shipping Alliance', 'Nhóm các hãng chia sẻ slot/space, phối hợp lịch trình. Tái cấu trúc 2/2025.', 'alliances, alliance_membership_history'),
('Gemini Cooperation', 'Gemini Cooperation', 'Liên minh mới Maersk + Hapag-Lloyd, từ 2/2025, mô hình hub-and-spoke. TCIT là hub VN.', 'alliances'),
('Premier Alliance', 'Premier Alliance', 'Liên minh ONE+HMM+YM từ 2/2025 (tái cấu trúc từ THE Alliance).', 'alliances'),
('Ocean Alliance', 'Ocean Alliance', 'CMA CGM+COSCO+EV+OOCL — gia hạn đến 2032. Lớn nhất toàn cầu.', 'alliances'),
('CM-TV', 'Cái Mép - Thị Vải', 'Cụm cảng nước sâu BRVT — gồm Gemalink, TCIT, CMIT, SSIT, SP-PSA, TCCT, TCTT.', 'ports.cluster'),
('ICD', 'Inland Container Depot', 'Cảng cạn — depot container nội địa.', 'ports.port_type'),
('Hub-and-spoke', 'Hub-and-spoke model', 'Mô hình tàu mẹ chỉ ghé 1-2 hub chính, feeder phân phối tới các port phụ.', 'services'),
('Cảng vụ', 'Maritime Administration', 'Cơ quan quản lý nhà nước về hàng hải, công bố lịch tàu công khai.', 'port_vessel_schedule_external.source'),
('Trade lane', 'Trade Lane', 'Tuyến thương mại chính: Asia-Europe, TransPacific, Intra-Asia, Asia-Middle East, Asia-Americas.', 'services.trade_lane'),
('Pareto 80/20', '80/20 Rule', 'Top 5 hãng tàu chiếm ~72% sản lượng Gemadept.', 'port_calls'),
('SAIDI', '-', 'Không áp dụng cho ngành cảng.', '-'),
('Reefer', 'Reefer Container', 'Container lạnh dùng cho hàng đông lạnh.', 'port_calls.reefer_teu'),
('Megaship', 'Mega Vessel', 'Tàu container ≥ 18,000 TEU. Chỉ Gemalink ở VN đón được megaship 250k DWT.', 'vessels.vessel_type');
